import Foundation

enum DegreeCareerDatabase {
    static func lookup(_ pathId: String) -> DegreeCareerDetailData? {
        let id = pathId.lowercased()
        return allData[id]
    }

    static func lookupByEducationId(_ eduId: String) -> DegreeCareerDetailData? {
        let id = eduId.lowercased()
        return allData[id] ?? educationIdMap[id]
    }

    static func record(for id: String) -> DegreeCareerRecord? {
        allRecords.first { $0.id == id }
    }

    static let allRecords: [DegreeCareerRecord] = healthcareRecords + mentalHealthRecords + engineeringRecords + legalRecords + educationRecords + aviationRecords + militaryRecords

